class Solution {
public:
    int lengthAfterTransformations(string s, int t, vector<int>& nums) {
        const int MOD = 1e9 + 7;
        vector<long long> dp(26, 1);
        for (int i = 0; i < t; i++) {
            vector<long long> next(26, 0);
            for (int j = 0; j < 26; j++) {
                next[(j + nums[j]) % 26] = (next[(j + nums[j]) % 26] + dp[j]) % MOD;
            }
            dp = next;
        }
        long long ans = 0;
        for (char c : s) {
            ans = (ans + dp[c - 'a']) % MOD;
        }
        return ans;
    }
};
